class Solution {
public:
    int firstMissingPositive(vector<int>& nums) {
        int n = nums.size();
        for (int& num: nums) {
            if (num <= 0) {
                num = n + 1; // 非正数改成 n+1，使其不参与后续标记
            }
        }
        for (int i = 0; i < n; ++i) {
            int num = abs(nums[i]);
            if (num <= n) {
                nums[num - 1] = -abs(nums[num - 1]); // 值 num 出现过：给下标 num-1 处打负号标记
            }
        }
        for (int i = 0; i < n; ++i) {
            if (nums[i] > 0) {
                return i + 1; // 第一个仍为正的位置，说明 i+1 未出现
            }
        }
        return n + 1;
    }
};
